import os
from dataclasses import dataclass


def _get_env(name: str, default: str) -> str:
    return os.getenv(name, default)


@dataclass(frozen=True)
class AzureConfig:
    storage_account: str = _get_env("AZURE_STORAGE_ACCOUNT", "nytaxistorage")
    container: str = _get_env("AZURE_STORAGE_CONTAINER", "taxi-data")
    raw_prefix: str = _get_env("AZURE_TAXI_RAW_PREFIX", "raw/taxi")
    bronze_prefix: str = _get_env("AZURE_TAXI_BRONZE_PREFIX", "bronze/taxi")
    silver_prefix: str = _get_env("AZURE_TAXI_CURATED_PREFIX", "silver/taxi")
    gold_prefix: str = _get_env("AZURE_TAXI_GOLD_PREFIX", "gold/taxi")


AZURE_CONFIG = AzureConfig()


def azure_path(prefix: str) -> str:
    return (
        f"abfss://{AZURE_CONFIG.container}@{AZURE_CONFIG.storage_account}"
        f".dfs.core.windows.net/{prefix.strip('/')}/"
    )


RAW_PATH = azure_path(AZURE_CONFIG.raw_prefix)
BRONZE_PATH = azure_path(AZURE_CONFIG.bronze_prefix)
SILVER_PATH = azure_path(AZURE_CONFIG.silver_prefix)
GOLD_PATH = azure_path(AZURE_CONFIG.gold_prefix)

from pyspark.sql import functions as F


def clean_taxi_data(df):
    return (
        df.filter(F.col("fare_amount").isNotNull())
        .filter(F.col("fare_amount") >= 0)
        .filter(F.col("trip_distance").isNotNull())
        .filter(F.col("tpep_pickup_datetime").isNotNull())
    )


def add_time_features(df):
    return df.withColumn("hour", F.hour(F.col("tpep_pickup_datetime")))


def aggregate_revenue_by_location(df):
    return (
        df.groupBy("PULocationID")
        .agg(
            F.sum("fare_amount").alias("total_revenue"),
            F.count("*").alias("trip_count"),
            F.avg("fare_amount").alias("avg_fare_amount"),
        )
        .orderBy(F.desc("total_revenue"))
